mapper.select:
SELECT sal.id, sal.product_id, p.product_code, COALESCE(sal.product_name_snapshot, p.product_name) AS productName, sal.before_quantity, sal.after_quantity, sal.change_quantity, sal.change_type, sal.biz_order_id, sal.biz_order_no, sal.operator_name, sal.reason, sal.remark, sal.created_time FROM stock_adjust_log sal LEFT JOIN product p ON sal.product_id = p.id
AND COALESCE(sal.product_name_snapshot, p.product_name) LIKE CONCAT('%', #{productName}, '%')
ORDER BY sal.id DESC LIMIT #{offset}, #{pageSize}
